// ---------------------------------------------------------------------------

func TestRapid_BuildPeerMap_Symmetry(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		users := genTestUsers(t)
		nodes := genTestNodesNoTags(t, users)
		polJSON := genSimplePolicy(t, users)

