package routes

import (
	"fmt"
	"net/netip"
	"slices"
	"sort"
	"testing"

	"github.com/juanfont/headscale/hscontrol/types"
	"pgregory.net/rapid"
	"tailscale.com/net/tsaddr"
)

// prefixPool is a fixed set of non-exit prefixes used in the PBT.
var prefixPool = []netip.Prefix{
	netip.MustParsePrefix("10.0.0.0/24"),
	netip.MustParsePrefix("10.0.1.0/24"),
	netip.MustParsePrefix("192.168.1.0/24"),
	netip.MustParsePrefix("192.168.2.0/24"),
	netip.MustParsePrefix("172.16.0.0/16"),
	netip.MustParsePrefix("fd00::/64"),
}

// exitRoutes are the prefixes that should always be filtered out.
var exitRoutes = []netip.Prefix{
	netip.MustParsePrefix("0.0.0.0/0"),
	netip.MustParsePrefix("::/0"),
}

// allGeneratable includes both normal and exit prefixes for the generator.
var allGeneratable = append(append([]netip.Prefix{}, prefixPool...), exitRoutes...)

// genNodeID draws a small NodeID from [1, 8].
func genNodeID(t *rapid.T) types.NodeID {
	return types.NodeID(rapid.IntRange(1, 8).Draw(t, "nodeID"))
}

// genPrefixes draws a subset of allGeneratable (including possible exit routes).
func genPrefixes(t *rapid.T) []netip.Prefix {
	return rapid.SliceOfNDistinct(
		rapid.SampledFrom(allGeneratable),
		0, len(allGeneratable),
		func(p netip.Prefix) string { return p.String() },
	).Draw(t, "prefixes")
}

// referenceModel is a simple model that tracks the same state as PrimaryRoutes
// but with a straightforward implementation for comparison.
type referenceModel struct {
	// routes maps nodeID -> set of non-exit prefixes.
	routes map[types.NodeID]map[netip.Prefix]struct{}

	// primaries maps prefix -> primary nodeID.
	// Mirrors PrimaryRoutes.primaries semantics:
	// - Stability: if old primary still advertises, keep it.
	// - Selection: lowest nodeID among advertisers for new primaries.
	primaries map[netip.Prefix]types.NodeID
}

func newReferenceModel() *referenceModel {
	return &referenceModel{
		routes:    make(map[types.NodeID]map[netip.Prefix]struct{}),
		primaries: make(map[netip.Prefix]types.NodeID),
	}
}

// setRoutes mirrors PrimaryRoutes.SetRoutes logic.
// Returns (new primaries snapshot, changed bool).
func (m *referenceModel) setRoutes(node types.NodeID, prefixes []netip.Prefix) (map[netip.Prefix]types.NodeID, bool) {
	// Filter out exit routes and build the set.
	filtered := make(map[netip.Prefix]struct{})
	for _, p := range prefixes {
		if !tsaddr.IsExitRoute(p) {
			filtered[p] = struct{}{}
		}
	}

	if len(filtered) == 0 {
		delete(m.routes, node)
	} else {
		m.routes[node] = filtered
	}

	return m.recalcPrimaries()
}

// recalcPrimaries mirrors updatePrimaryLocked.
func (m *referenceModel) recalcPrimaries() (map[netip.Prefix]types.NodeID, bool) {
	// Build prefix -> sorted list of advertisers.
	advertisers := make(map[netip.Prefix][]types.NodeID)
	for nid, prefixes := range m.routes {
		for p := range prefixes {
			advertisers[p] = append(advertisers[p], nid)
		}
	}
	// Sort each list by NodeID (ascending).
	for p := range advertisers {
		sort.Slice(advertisers[p], func(i, j int) bool {
			return advertisers[p][i] < advertisers[p][j]
		})
	}

	changed := false

	// For each prefix with advertisers, determine primary.
	for prefix, nodes := range advertisers {
		if currentPrimary, ok := m.primaries[prefix]; ok {
			if slices.Contains(nodes, currentPrimary) {
				// Stability: current primary still advertises, keep it.
				continue
			}
		}
		// New primary needed: pick lowest NodeID.
		m.primaries[prefix] = nodes[0]
		changed = true
	}

	// Clean up primaries for prefixes no longer advertised.
	for prefix := range m.primaries {
		if _, ok := advertisers[prefix]; !ok {
			delete(m.primaries, prefix)
			changed = true
		}
	}

	// Return a snapshot of the primaries.
	snap := make(map[netip.Prefix]types.NodeID, len(m.primaries))
	for k, v := range m.primaries {
		snap[k] = v
	}
	return snap, changed
}

// primaryRoutesFor returns sorted primaries for a node (mirrors PrimaryRoutes.PrimaryRoutes).
func (m *referenceModel) primaryRoutesFor(id types.NodeID) []netip.Prefix {
	var routes []netip.Prefix
	for prefix, nid := range m.primaries {
		if nid == id {
			routes = append(routes, prefix)
		}
	}
	slices.SortFunc(routes, netip.Prefix.Compare)
	return routes
}

// snapshotPrimaries returns a copy of pr.primaries for comparison.
// Must be called while holding the lock or when no concurrent access exists.
func snapshotPrimaries(pr *PrimaryRoutes) map[netip.Prefix]types.NodeID {
	snap := make(map[netip.Prefix]types.NodeID, len(pr.primaries))
	for k, v := range pr.primaries {
		snap[k] = v
	}
	return snap
}

func TestPrimaryRoutesRapid(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		pr := New()
		model := newReferenceModel()

		t.Repeat(map[string]func(*rapid.T){
			"AddRoutes": func(t *rapid.T) {
				node := genNodeID(t)
				prefixes := genPrefixes(t)

				// Snapshot the primaries before the operation to check changed flag.
				pr.mu.Lock()
				beforePrimaries := snapshotPrimaries(pr)
				pr.mu.Unlock()

				gotChanged := pr.SetRoutes(node, prefixes...)
				_, modelChanged := model.setRoutes(node, prefixes)

				// Lock to inspect internal state for invariant checks.
				pr.mu.Lock()
				defer pr.mu.Unlock()

				checkInvariants(t, pr, model, beforePrimaries, gotChanged, modelChanged,
					fmt.Sprintf("AddRoutes(node=%d, prefixes=%v)", node, prefixes))
			},

			"RemoveNode": func(t *rapid.T) {
				node := genNodeID(t)

				pr.mu.Lock()
				beforePrimaries := snapshotPrimaries(pr)
				pr.mu.Unlock()

				gotChanged := pr.SetRoutes(node) // empty = remove
				_, modelChanged := model.setRoutes(node, nil)

				pr.mu.Lock()
				defer pr.mu.Unlock()

				checkInvariants(t, pr, model, beforePrimaries, gotChanged, modelChanged,
					fmt.Sprintf("RemoveNode(node=%d)", node))
			},

			"QueryPrimary": func(t *rapid.T) {
				node := genNodeID(t)

				gotRoutes := pr.PrimaryRoutes(node)
				wantRoutes := model.primaryRoutesFor(node)

				// Normalize nil vs empty for comparison.
				if len(gotRoutes) == 0 {
					gotRoutes = nil
				}
				if len(wantRoutes) == 0 {
					wantRoutes = nil
				}

				if !slices.Equal(gotRoutes, wantRoutes) {
					t.Fatalf("QueryPrimary(node=%d): got %v, want %v",
						node, gotRoutes, wantRoutes)
				}
			},
		})
	})
}

// checkInvariants verifies all required invariants hold after an operation.
// Caller must hold pr.mu.
func checkInvariants(
	t *rapid.T,
	pr *PrimaryRoutes,
	model *referenceModel,
	beforePrimaries map[netip.Prefix]types.NodeID,
	gotChanged bool,
	modelChanged bool,
	opDesc string,
) {
	// 1. Changed flag matches model.
	if gotChanged != modelChanged {
		t.Fatalf("%s: changed mismatch: got %v, model %v\nprimaries: %v\nmodel primaries: %v",
			opDesc, gotChanged, modelChanged, pr.primaries, model.primaries)
	}

	// 2. Changed flag is consistent with actual state delta.
	afterPrimaries := snapshotPrimaries(pr)
	actuallyChanged := !primariesEqual(beforePrimaries, afterPrimaries)
	if gotChanged != actuallyChanged {
		t.Fatalf("%s: changed=%v but before/after comparison says changed=%v\nbefore: %v\nafter: %v",
			opDesc, gotChanged, actuallyChanged, beforePrimaries, afterPrimaries)
	}

	// 3. Primaries match the reference model exactly.
	if len(pr.primaries) != len(model.primaries) {
		t.Fatalf("%s: primaries count mismatch: got %d, want %d\ngot: %v\nwant: %v",
			opDesc, len(pr.primaries), len(model.primaries), pr.primaries, model.primaries)
	}
	for prefix, gotNode := range pr.primaries {
		wantNode, ok := model.primaries[prefix]
		if !ok {
			t.Fatalf("%s: prefix %s in SUT primaries but not in model", opDesc, prefix)
		}
		if gotNode != wantNode {
			t.Fatalf("%s: primary for %s: got node %d, want %d", opDesc, prefix, gotNode, wantNode)
		}
	}

	// 4. Exactly one primary per advertised prefix (no prefix without primary).
	allAdvertised := make(map[netip.Prefix]bool)
	for _, prefixes := range pr.routes {
		for p := range prefixes {
			allAdvertised[p] = true
		}
	}
	for prefix := range allAdvertised {
		if _, ok := pr.primaries[prefix]; !ok {
			t.Fatalf("%s: prefix %s is advertised but has no primary", opDesc, prefix)
		}
	}

	// 5. No orphaned primaries (primary for prefix with no advertisers).
	for prefix := range pr.primaries {
		if !allAdvertised[prefix] {
			t.Fatalf("%s: prefix %s has a primary but no advertisers", opDesc, prefix)
		}
	}

	// 6. Primary must be a valid advertiser for the prefix.
	for prefix, nodeID := range pr.primaries {
		routes, ok := pr.routes[nodeID]
		if !ok {
			t.Fatalf("%s: primary node %d for prefix %s has no routes at all",
				opDesc, nodeID, prefix)
		}
		if !routes.Contains(prefix) {
			t.Fatalf("%s: primary node %d for prefix %s does not advertise that prefix",
				opDesc, nodeID, prefix)
		}
	}

	// 7. No exit routes stored in the system.
	for _, prefixes := range pr.routes {
		for p := range prefixes {
			if tsaddr.IsExitRoute(p) {
				t.Fatalf("%s: exit route %s found in routes", opDesc, p)
			}
		}
	}
	for p := range pr.primaries {
		if tsaddr.IsExitRoute(p) {
			t.Fatalf("%s: exit route %s found in primaries", opDesc, p)
		}
	}

	// 8. isPrimary index consistency.
	//    isPrimary should have exactly the set of nodeIDs that appear as values in primaries.
	expectedIsPrimary := make(map[types.NodeID]bool)
	for _, nodeID := range pr.primaries {
		expectedIsPrimary[nodeID] = true
	}
	if len(pr.isPrimary) != len(expectedIsPrimary) {
		t.Fatalf("%s: isPrimary size mismatch: got %d, want %d\ngot: %v\nwant: %v",
			opDesc, len(pr.isPrimary), len(expectedIsPrimary), pr.isPrimary, expectedIsPrimary)
	}
	for nodeID, val := range pr.isPrimary {
		if !val {
			t.Fatalf("%s: isPrimary[%d] = false, should not be in map", opDesc, nodeID)
		}
		if !expectedIsPrimary[nodeID] {
			t.Fatalf("%s: node %d in isPrimary but not a primary for any prefix", opDesc, nodeID)
		}
	}
	for nodeID := range expectedIsPrimary {
		if !pr.isPrimary[nodeID] {
			t.Fatalf("%s: node %d is a primary but missing from isPrimary index", opDesc, nodeID)
		}
	}

	// 9. Stability: if old primary still advertises the prefix, it must remain primary.
	for prefix, beforeNode := range beforePrimaries {
		if afterNode, ok := pr.primaries[prefix]; ok {
			// Check if the old primary still advertises this prefix.
			if routes, rok := pr.routes[beforeNode]; rok && routes.Contains(prefix) {
				if afterNode != beforeNode {
					t.Fatalf("%s: stability violation: prefix %s had primary %d which still advertises, but primary changed to %d",
						opDesc, prefix, beforeNode, afterNode)
				}
			}
		}
	}

	// 10. Deterministic selection: for new primaries (prefix not in before or
	//     old primary no longer advertises), the lowest NodeID must be chosen.
	for prefix, afterNode := range pr.primaries {
		beforeNode, wasPrimary := beforePrimaries[prefix]
		isNewSelection := false
		if !wasPrimary {
			// Entirely new prefix.
			isNewSelection = true
		} else {
			// Check if old primary stopped advertising.
			routes, rok := pr.routes[beforeNode]
			if !rok || !routes.Contains(prefix) {
				isNewSelection = true
			}
		}
		if isNewSelection {
			// Find the lowest NodeID that advertises this prefix.
			var lowestID types.NodeID
			first := true
			for nid, prefixes := range pr.routes {
				if prefixes.Contains(prefix) {
					if first || nid < lowestID {
						lowestID = nid
						first = false
					}
				}
			}
			if afterNode != lowestID {
				t.Fatalf("%s: deterministic selection violation: prefix %s should have primary %d (lowest advertiser), got %d",
					opDesc, prefix, lowestID, afterNode)
			}
		}
	}
}

// primariesEqual compares two primaries maps for equality.
func primariesEqual(a, b map[netip.Prefix]types.NodeID) bool {
	if len(a) != len(b) {
		return false
	}
	for k, v := range a {
		if bv, ok := b[k]; !ok || bv != v {
			return false
		}
	}
	return true
}

package servertest_test

import (
	"fmt"
	"net/netip"
	"testing"
	"time"

	"github.com/juanfont/headscale/hscontrol/servertest"
	"pgregory.net/rapid"
	"tailscale.com/tailcfg"
)

// meshState is the model that tracks expected state alongside the
// real harness. It records which client indices are connected vs
// disconnected so invariant checks can filter appropriately.
type meshState struct {
	harness *servertest.TestHarness

	// tb is the real *testing.T used for harness operations that
	// require testing.TB (TempDir, Cleanup, etc). Infrastructure
	// failures (server creation, client registration) abort the
	// test immediately.
	tb testing.TB

	// connected tracks whether each client index is currently
	// connected (true) or disconnected (false).
	connected []bool

	// totalAdded is the total number of clients ever added
	// (including the initial set). Equals len(harness.Clients()).
	totalAdded int

	// currentPolicy tracks which policy is active for logging.
	currentPolicy string
}

// connectedClients returns the TestClient pointers for all clients
// that the model believes are connected.
func (m *meshState) connectedClients() []*servertest.TestClient {
	var out []*servertest.TestClient

	for i, c := range m.connected {
		if c {
			out = append(out, m.harness.Client(i))
		}
	}

	return out
}

// connectedIndices returns the indices of connected clients.
func (m *meshState) connectedIndices() []int {
	var out []int

	for i, c := range m.connected {
		if c {
			out = append(out, i)
		}
	}

	return out
}

// disconnectedIndices returns the indices of disconnected clients.
func (m *meshState) disconnectedIndices() []int {
	var out []int

	for i, c := range m.connected {
		if !c {
			out = append(out, i)
		}
	}

	return out
}

// connectedCount returns the number of currently connected clients.
func (m *meshState) connectedCount() int {
	n := 0

	for _, c := range m.connected {
		if c {
			n++
		}
	}

	return n
}

// policyEntry pairs a human-readable label with a HuJSON policy doc.
type policyEntry struct {
	label string
	doc   []byte
}

// policyPool is the set of ACL policies that can be randomly applied.
// All policies grant full connectivity (with different rule shapes)
// so that peer visibility invariants hold regardless of which policy
// is active.
var policyPool = []policyEntry{
	{
		label: "allow-all",
		doc: []byte(`{
			"acls": [
				{"action": "accept", "src": ["*"], "dst": ["*:*"]}
			]
		}`),
	},
	{
		label: "allow-all-tcp",
		doc: []byte(`{
			"acls": [
				{"action": "accept", "src": ["*"], "dst": ["*:*"], "proto": "tcp"}
			]
		}`),
	},
	{
		label: "allow-all-with-autogroup",
		doc: []byte(`{
			"acls": [
				{"action": "accept", "src": ["autogroup:member"], "dst": ["autogroup:member:*"]}
			]
		}`),
	},
}

// meshConvergenceTimeout is the maximum time to wait for the mesh
// to converge after an operation. This must be generous because the
// batcher coalesces changes with a 50ms delay, and propagation
// through poll -> mapper -> controlclient adds latency.
const meshConvergenceTimeout = 30 * time.Second

// checkMeshInvariants verifies all mesh invariants against the
// currently-connected clients. It uses rt.Fatalf for failures so
// that rapid can shrink the failing operation sequence.
func checkMeshInvariants(rt *rapid.T, m *meshState, opDesc string) {
	connected := m.connectedClients()
	if len(connected) == 0 {
		return // nothing to check
	}

	// Invariant 1: All connected clients have a non-nil netmap with
	// non-empty self-addresses.
	for _, c := range connected {
		nm := c.Netmap()
		if nm == nil {
			rt.Fatalf("%s: invariant violation: client %s has nil netmap",
				opDesc, c.Name)

			return // unreachable, but silences SA5011
		}

		if !nm.SelfNode.Valid() {
			rt.Fatalf("%s: invariant violation: client %s has invalid SelfNode",
				opDesc, c.Name)

			return
		}

		if nm.SelfNode.Addresses().Len() == 0 {
			rt.Fatalf("%s: invariant violation: client %s self node has no addresses",
				opDesc, c.Name)
		}
	}

	// Invariant 2: Consistent peer counts among connected clients.
	// All connected clients should see at least (connectedCount - 1)
	// peers. Non-ephemeral disconnected nodes may still appear in
	// peer lists, so we check >= rather than ==.
	expectedMinPeers := len(connected) - 1

	for _, c := range connected {
		nm := c.Netmap()
		if nm == nil {
			continue
		}

		if len(nm.Peers) < expectedMinPeers {
			rt.Fatalf("%s: invariant violation: client %s has %d peers, "+
				"want >= %d (peers: %v)",
				opDesc, c.Name, len(nm.Peers), expectedMinPeers,
				c.PeerNames())
		}
	}

	// Invariant 3: Peer visibility is symmetric among connected
	// clients. If connected client A sees connected client B, then
	// B must also see A.
	for _, a := range connected {
		for _, b := range connected {
			if a == b {
				continue
			}

			_, aSeesB := a.PeerByName(b.Name)
			_, bSeesA := b.PeerByName(a.Name)

			if aSeesB != bSeesA {
				rt.Fatalf("%s: invariant violation: asymmetric visibility: "+
					"%s sees %s = %v, but %s sees %s = %v",
					opDesc, a.Name, b.Name, aSeesB,
					b.Name, a.Name, bSeesA)
			}
		}
	}

	// Invariant 4: DERP map is present on all connected clients.
	for _, c := range connected {
		nm := c.Netmap()
		if nm == nil {
			continue
		}

		if nm.DERPMap == nil {
			rt.Fatalf("%s: invariant violation: client %s has nil DERPMap",
				opDesc, c.Name)
		}

		if len(nm.DERPMap.Regions) == 0 {
			rt.Fatalf("%s: invariant violation: client %s has empty DERPMap regions",
				opDesc, c.Name)
		}
	}

	// Invariant 5: No duplicate node IDs across clients.
	seenIDs := make(map[tailcfg.NodeID]string)

	for _, c := range connected {
		nm := c.Netmap()
		if nm == nil || !nm.SelfNode.Valid() {
			continue
		}

		id := nm.SelfNode.ID()
		if prev, exists := seenIDs[id]; exists {
			rt.Fatalf("%s: invariant violation: duplicate node ID %d: "+
				"clients %s and %s", opDesc, id, prev, c.Name)
		}

		seenIDs[id] = c.Name
	}

	// Invariant 6: IP addresses are unique across all clients.
	seenAddrs := make(map[netip.Prefix]string)

	for _, c := range connected {
		nm := c.Netmap()
		if nm == nil || !nm.SelfNode.Valid() {
			continue
		}

		for i := range nm.SelfNode.Addresses().Len() {
			addr := nm.SelfNode.Addresses().At(i)
			if prev, exists := seenAddrs[addr]; exists {
				rt.Fatalf("%s: invariant violation: duplicate IP %s: "+
					"clients %s and %s", opDesc, addr, prev, c.Name)
			}

			seenAddrs[addr] = c.Name
		}
	}
}

// awaitMeshConvergence polls until all connected clients see at
// least the expected number of peers, or until timeout expires.
// Returns false if convergence did not happen in time.
//
//nolint:unparam // timeout parameter kept for flexibility in future callers
func awaitMeshConvergence(m *meshState, timeout time.Duration) bool {
	connected := m.connectedClients()
	if len(connected) <= 1 {
		// 0 or 1 connected clients: just ensure the single client
		// has a netmap if present.
		if len(connected) == 1 {
			deadline := time.After(timeout)

			for {
				if nm := connected[0].Netmap(); nm != nil {
					return true
				}

				select {
				case <-deadline:
					return false
				case <-time.After(100 * time.Millisecond):
				}
			}
		}

		return true
	}

	expectedPeers := len(connected) - 1
	deadline := time.After(timeout)

	for {
		allGood := true

		for _, c := range connected {
			nm := c.Netmap()
			if nm == nil || len(nm.Peers) < expectedPeers {
				allGood = false

				break
			}
		}

		if allGood {
			return true
		}

		select {
		case <-deadline:
			return false
		case <-time.After(100 * time.Millisecond):
		}
	}
}

// TestRapidMeshOperations is a stateful property-based test that
// generates random sequences of mesh operations (add client,
// disconnect, reconnect, change policy) against a real in-process
// Headscale server, then checks invariants after each operation.
//
// Architecture: the outer *testing.T is captured for harness
// operations (NewHarness, AddClient, Disconnect, etc.) which
// require testing.TB for TempDir/Cleanup. The inner *rapid.T is
// used for random data generation and property assertions so that
// rapid can shrink failing sequences.
//
// This tests the FULL STACK: HTTP -> Noise -> poll -> batcher ->
// mapper -> controlclient, with random operation sequences that
// would be impossible to explore with handwritten tests.
func TestRapidMeshOperations(t *testing.T) {
	t.Parallel()

	rapid.Check(t, func(rt *rapid.T) {
		// Universe: create a server + 1 default user + 3-5 initial clients.
		initialCount := rapid.IntRange(3, 5).Draw(rt, "initialClients")

		h := servertest.NewHarness(t, initialCount,
			servertest.WithServerOptions(
				servertest.WithBatchDelay(50*time.Millisecond),
			),
			servertest.WithConvergenceTimeout(meshConvergenceTimeout),
		)

		state := &meshState{
			harness:       h,
			tb:            t,
			connected:     make([]bool, initialCount),
			totalAdded:    initialCount,
			currentPolicy: "default (no policy)",
		}

		// Mark all initial clients as connected.
		for i := range initialCount {
			state.connected[i] = true
		}

		// The harness already waited for mesh convergence, so
		// check invariants on the initial state.
		checkMeshInvariants(rt, state, "initial mesh formation")

		// Stateful property test: generate random operations.
		rt.Repeat(map[string]func(*rapid.T){
			// AddClient: add a new client to the mesh.
			// Capped at 10 total clients to keep test runtime
			// reasonable.
			"AddClient": func(rt *rapid.T) {
				if state.totalAdded >= 10 {
					rt.Skip("max clients reached")
				}

				_ = state.harness.AddClient(t)
				state.connected = append(state.connected, true)
				state.totalAdded++

				opDesc := fmt.Sprintf("AddClient(total=%d)", state.totalAdded)

				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("%s: mesh did not converge within %v "+
						"(connected=%d)",
						opDesc, meshConvergenceTimeout,
						state.connectedCount())
				}

				checkMeshInvariants(rt, state, opDesc)
			},

			// DisconnectClient: disconnect a random connected client.
			"DisconnectClient": func(rt *rapid.T) {
				indices := state.connectedIndices()
				if len(indices) <= 1 {
					rt.Skip("too few connected clients to disconnect")
				}

				idx := rapid.SampledFrom(indices).Draw(rt, "disconnectIdx")
				client := state.harness.Client(idx)
				client.Disconnect(t)

				state.connected[idx] = false

				opDesc := fmt.Sprintf("DisconnectClient(%s, idx=%d)",
					client.Name, idx)

				// After disconnection, wait for remaining connected
				// clients to converge.
				if remaining := state.connectedCount(); remaining > 1 {
					if !awaitMeshConvergence(state, meshConvergenceTimeout) {
						rt.Fatalf("%s: mesh did not converge within %v "+
							"(connected=%d)",
							opDesc, meshConvergenceTimeout, remaining)
					}
				}

				checkMeshInvariants(rt, state, opDesc)
			},

			// ReconnectClient: reconnect a previously disconnected
			// client.
			"ReconnectClient": func(rt *rapid.T) {
				indices := state.disconnectedIndices()
				if len(indices) == 0 {
					rt.Skip("no disconnected clients to reconnect")
				}

				idx := rapid.SampledFrom(indices).Draw(rt, "reconnectIdx")
				client := state.harness.Client(idx)
				client.Reconnect(t)

				state.connected[idx] = true

				opDesc := fmt.Sprintf("ReconnectClient(%s, idx=%d)",
					client.Name, idx)

				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("%s: mesh did not converge within %v "+
						"(connected=%d)",
						opDesc, meshConvergenceTimeout,
						state.connectedCount())
				}

				checkMeshInvariants(rt, state, opDesc)
			},

			// ChangePolicy: apply a random ACL policy.
			"ChangePolicy": func(rt *rapid.T) {
				pol := rapid.SampledFrom(policyPool).Draw(rt, "policy")

				state.harness.ChangePolicy(t, pol.doc)
				state.currentPolicy = pol.label

				opDesc := fmt.Sprintf("ChangePolicy(%s)", pol.label)

				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("%s: mesh did not converge within %v "+
						"(connected=%d)",
						opDesc, meshConvergenceTimeout,
						state.connectedCount())
				}

				checkMeshInvariants(rt, state, opDesc)
			},

			// WaitAndCheck: wait for convergence and verify
			// invariants. This is a no-op operation that gives the
			// system time to settle.
			"WaitAndCheck": func(rt *rapid.T) {
				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("WaitAndCheck: mesh did not converge "+
						"within %v (connected=%d, total=%d, policy=%s)",
						meshConvergenceTimeout,
						state.connectedCount(),
						state.totalAdded,
						state.currentPolicy)
				}

				checkMeshInvariants(rt, state, "WaitAndCheck")
			},
		})
	})
}

// TestRapidMeshChurn is a focused variant that generates longer
// sequences of disconnect/reconnect operations to stress-test the
// session replacement and grace period logic.
func TestRapidMeshChurn(t *testing.T) {
	t.Parallel()

	rapid.Check(t, func(rt *rapid.T) {
		const initialCount = 4

		h := servertest.NewHarness(t, initialCount,
			servertest.WithServerOptions(
				servertest.WithBatchDelay(50*time.Millisecond),
			),
			servertest.WithConvergenceTimeout(meshConvergenceTimeout),
		)

		state := &meshState{
			harness:       h,
			tb:            t,
			connected:     []bool{true, true, true, true},
			totalAdded:    initialCount,
			currentPolicy: "default",
		}

		checkMeshInvariants(rt, state, "initial churn mesh")

		rt.Repeat(map[string]func(*rapid.T){
			"Disconnect": func(rt *rapid.T) {
				indices := state.connectedIndices()
				if len(indices) <= 1 {
					rt.Skip("need at least 1 connected")
				}

				idx := rapid.SampledFrom(indices).Draw(rt, "disconnectIdx")
				state.harness.Client(idx).Disconnect(t)

				state.connected[idx] = false
			},

			"Reconnect": func(rt *rapid.T) {
				indices := state.disconnectedIndices()
				if len(indices) == 0 {
					rt.Skip("no disconnected clients")
				}

				idx := rapid.SampledFrom(indices).Draw(rt, "reconnectIdx")
				state.harness.Client(idx).Reconnect(t)

				state.connected[idx] = true
			},

			"ConvergeAndCheck": func(rt *rapid.T) {
				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("churn: mesh did not converge "+
						"(connected=%d)",
						state.connectedCount())
				}

				checkMeshInvariants(rt, state, "churn:ConvergeAndCheck")
			},
		})

		// Final convergence check after all operations.
		if !awaitMeshConvergence(state, meshConvergenceTimeout) {
			rt.Fatalf("churn: final convergence failed (connected=%d)",
				state.connectedCount())
		}

		checkMeshInvariants(rt, state, "churn:final")
	})
}

// TestRapidPolicyToggle focuses on rapid policy changes interleaved
// with client additions, verifying that policy propagation never
// leaves clients in an inconsistent state.
func TestRapidPolicyToggle(t *testing.T) {
	t.Parallel()

	rapid.Check(t, func(rt *rapid.T) {
		initialCount := rapid.IntRange(2, 4).Draw(rt, "initialClients")

		h := servertest.NewHarness(t, initialCount,
			servertest.WithServerOptions(
				servertest.WithBatchDelay(50*time.Millisecond),
			),
			servertest.WithConvergenceTimeout(meshConvergenceTimeout),
		)

		state := &meshState{
			harness:       h,
			tb:            t,
			connected:     make([]bool, initialCount),
			totalAdded:    initialCount,
			currentPolicy: "default",
		}

		for i := range initialCount {
			state.connected[i] = true
		}

		checkMeshInvariants(rt, state, "initial policy-toggle mesh")

		rt.Repeat(map[string]func(*rapid.T){
			"ChangePolicy": func(rt *rapid.T) {
				pol := rapid.SampledFrom(policyPool).Draw(rt, "policy")
				state.harness.ChangePolicy(t, pol.doc)
				state.currentPolicy = pol.label

				opDesc := fmt.Sprintf("ChangePolicy(%s)", pol.label)

				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("%s: convergence failed", opDesc)
				}

				checkMeshInvariants(rt, state, opDesc)

				// Additional check: all connected clients should
				// have received at least one update since the test
				// began.
				for _, c := range state.connectedClients() {
					if c.UpdateCount() == 0 {
						rt.Fatalf("%s: client %s has 0 updates "+
							"after policy change",
							opDesc, c.Name)
					}
				}
			},

			"AddClient": func(rt *rapid.T) {
				if state.totalAdded >= 8 {
					rt.Skip("max clients reached")
				}

				_ = state.harness.AddClient(t)
				state.connected = append(state.connected, true)
				state.totalAdded++

				opDesc := fmt.Sprintf(
					"AddClient(total=%d, policy=%s)",
					state.totalAdded, state.currentPolicy)

				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("%s: convergence failed", opDesc)
				}

				checkMeshInvariants(rt, state, opDesc)
			},

			"Check": func(rt *rapid.T) {
				if !awaitMeshConvergence(state, meshConvergenceTimeout) {
					rt.Fatalf("Check: convergence failed "+
						"(connected=%d, policy=%s)",
						state.connectedCount(),
						state.currentPolicy)
				}

				checkMeshInvariants(rt, state, "Check")
			},
		})
	})
}

package state

import (
	"cmp"
	"fmt"
	"net/netip"
	"slices"
	"testing"

	"github.com/juanfont/headscale/hscontrol/types"
	"pgregory.net/rapid"
	"tailscale.com/types/key"
)

// ============================================================================
// Generators
// ============================================================================

// genNodeID generates a NodeID in a small range to encourage key collisions
// during map-based generation while remaining large enough for meaningful tests.
func genNodeID() *rapid.Generator[types.NodeID] {
	return rapid.Custom[types.NodeID](func(t *rapid.T) types.NodeID {
		return types.NodeID(rapid.Uint64Range(1, 200).Draw(t, "nodeID"))
	})
}

// genUserID generates a UserID in a small range to create multi-node-per-user scenarios.
func genUserID() *rapid.Generator[uint] {
	return rapid.Custom[uint](func(t *rapid.T) uint {
		return uint(rapid.IntRange(1, 10).Draw(t, "userID"))
	})
}

// genTag generates a tag string in the form "tag:name".
func genTag() *rapid.Generator[string] {
	return rapid.Custom[string](func(t *rapid.T) string {
		name := rapid.StringMatching(`[a-z][a-z0-9]{0,7}`).Draw(t, "tagname")
		return "tag:" + name
	})
}

// genTags generates a slice of 0..maxLen unique tags.
func genTags(maxLen int) *rapid.Generator[[]string] {
	return rapid.Custom[[]string](func(t *rapid.T) []string {
		n := rapid.IntRange(0, maxLen).Draw(t, "numTags")
		seen := make(map[string]bool, n)
		result := make([]string, 0, n)
		for len(result) < n {
			tag := genTag().Draw(t, "tag")
			if !seen[tag] {
				seen[tag] = true
				result = append(result, tag)
			}
		}
		return result
	})
}

// genNode generates a random Node with random keys, IPs, user, and optional tags.
func genNode() *rapid.Generator[types.Node] {
	return rapid.Custom[types.Node](func(t *rapid.T) types.Node {
		id := genNodeID().Draw(t, "id")
		uid := genUserID().Draw(t, "uid")
		tags := genTags(3).Draw(t, "tags")

		machineKey := key.NewMachine()
		nodeKey := key.NewNode()
		discoKey := key.NewDisco()

		// Generate deterministic IPs from the node ID to avoid collisions in
		// simple cases but still have meaningful values.
		ipv4 := netip.AddrFrom4([4]byte{
			100,
			64,
			byte(id >> 8),   //nolint:gosec
			byte(id & 0xFF), //nolint:gosec
		})
		ipv6Bytes := [16]byte{0xfd, 0x7a, 0x11, 0x5c, 0xa1, 0xe0}
		ipv6Bytes[14] = byte(id >> 8)   //nolint:gosec
		ipv6Bytes[15] = byte(id & 0xFF) //nolint:gosec
		ipv6 := netip.AddrFrom16(ipv6Bytes)

		hostname := fmt.Sprintf("node-%d", id)

		return types.Node{
			ID:         id,
			MachineKey: machineKey.Public(),
			NodeKey:    nodeKey.Public(),
			DiscoKey:   discoKey.Public(),
			Hostname:   hostname,
			GivenName:  hostname,
			UserID:     new(uid),
			User: &types.User{
				Name:        fmt.Sprintf("user-%d", uid),
				DisplayName: fmt.Sprintf("User %d", uid),
			},
			RegisterMethod: "test",
			IPv4:           &ipv4,
			IPv6:           &ipv6,
			Tags:           tags,
		}
	})
}

// genNodeMap generates a map of NodeID -> Node with unique IDs.
// The map size is bounded to keep tests fast.
func genNodeMap(maxSize int) *rapid.Generator[map[types.NodeID]types.Node] {
	return rapid.Custom[map[types.NodeID]types.Node](func(t *rapid.T) map[types.NodeID]types.Node {
		n := rapid.IntRange(0, maxSize).Draw(t, "mapSize")
		nodes := make(map[types.NodeID]types.Node, n)
		for len(nodes) < n {
			node := genNode().Draw(t, "node")
			// Overwrite if ID exists; that's fine for unique-ID maps.
			nodes[node.ID] = node
		}
		return nodes
	})
}

// ============================================================================
// PeersFunc implementations
// ============================================================================

// allVisiblePeersFunc: every node sees every other node.
func allVisiblePeersFunc(nodes []types.NodeView) map[types.NodeID][]types.NodeView {
	ret := make(map[types.NodeID][]types.NodeView, len(nodes))
	for _, node := range nodes {
		var peers []types.NodeView
		for _, n := range nodes {
			if n.ID() != node.ID() {
				peers = append(peers, n)
			}
		}
		ret[node.ID()] = peers
	}
	return ret
}

// noVisiblePeersFunc: no node sees any other node.
func noVisiblePeersFunc(nodes []types.NodeView) map[types.NodeID][]types.NodeView {
	ret := make(map[types.NodeID][]types.NodeView, len(nodes))
	for _, node := range nodes {
		ret[node.ID()] = nil
	}
	return ret
}

// symmetricRandomPeersFunc builds a PeersFunc from a pre-computed symmetric
// adjacency set. By constructing the adjacency before the PeersFunc is called,
// we guarantee symmetry: if Y is in peers(X), then X is in peers(Y).
func symmetricRandomPeersFunc(t *rapid.T, ids []types.NodeID) PeersFunc {
	// Build a symmetric adjacency set.
	type edge struct{ a, b types.NodeID }
	adj := make(map[types.NodeID]map[types.NodeID]bool)
	for _, id := range ids {
		adj[id] = make(map[types.NodeID]bool)
	}

	for i := 0; i < len(ids); i++ {
		for j := i + 1; j < len(ids); j++ {
			if rapid.Bool().Draw(t, fmt.Sprintf("edge-%d-%d", ids[i], ids[j])) {
				adj[ids[i]][ids[j]] = true
				adj[ids[j]][ids[i]] = true
			}
		}
	}

	return func(nodes []types.NodeView) map[types.NodeID][]types.NodeView {
		ret := make(map[types.NodeID][]types.NodeView, len(nodes))
		nodesByID := make(map[types.NodeID]types.NodeView, len(nodes))
		for _, n := range nodes {
			nodesByID[n.ID()] = n
		}

		for _, node := range nodes {
			var peers []types.NodeView
			for peerID := range adj[node.ID()] {
				if pv, ok := nodesByID[peerID]; ok {
					peers = append(peers, pv)
				}
			}
			ret[node.ID()] = peers
		}
		return ret
	}
}

// genPeersFunc picks one of the three PeersFunc strategies.
// For symmetricRandom, we need the node IDs ahead of time so the
// adjacency can be pre-computed.
func genPeersFunc(t *rapid.T, ids []types.NodeID) PeersFunc {
	strategy := rapid.IntRange(0, 2).Draw(t, "peersFuncStrategy")
	switch strategy {
	case 0:
		return allVisiblePeersFunc
	case 1:
		return noVisiblePeersFunc
	default:
		return symmetricRandomPeersFunc(t, ids)
	}
}

// nodeIDs extracts sorted IDs from a node map.
func nodeIDs(nodes map[types.NodeID]types.Node) []types.NodeID {
	ids := make([]types.NodeID, 0, len(nodes))
	for id := range nodes {
		ids = append(ids, id)
	}
	slices.SortFunc(ids, func(a, b types.NodeID) int {
		return cmp.Compare(a, b)
	})
	return ids
}

// ============================================================================
// Property 1: allNodes count matches input
// ============================================================================

func TestRapid_Snapshot_AllNodesCount(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		if len(snap.allNodes) != len(nodes) {
			t.Fatalf("allNodes count %d != input count %d", len(snap.allNodes), len(nodes))
		}
	})
}

// ============================================================================
// Property 2: nodesByID completeness — every input node is in nodesByID
// ============================================================================

func TestRapid_Snapshot_NodesByIDCompleteness(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		for id, node := range nodes {
			got, ok := snap.nodesByID[id]
			if !ok {
				t.Fatalf("node %d missing from nodesByID", id)
			}
			if got.ID != node.ID {
				t.Fatalf("nodesByID[%d].ID = %d, want %d", id, got.ID, node.ID)
			}
		}

		// Reverse: nothing extra in nodesByID
		if len(snap.nodesByID) != len(nodes) {
			t.Fatalf("nodesByID has %d entries, input has %d", len(snap.nodesByID), len(nodes))
		}
	})
}

// ============================================================================
// Property 3: nodesByNodeKey consistency — every nodesByID entry has a
// corresponding entry in nodesByNodeKey
// ============================================================================

func TestRapid_Snapshot_NodesByNodeKeyConsistency(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		for _, node := range snap.nodesByID {
			nv, ok := snap.nodesByNodeKey[node.NodeKey]
			if !ok {
				t.Fatalf("node %d (NodeKey=%s) missing from nodesByNodeKey",
					node.ID, node.NodeKey.ShortString())
			}
			if nv.ID() != node.ID {
				t.Fatalf("nodesByNodeKey lookup for node %d returned node %d",
					node.ID, nv.ID())
			}
		}
	})
}

// ============================================================================
// Property 4: nodesByMachineKey consistency — every node can be found via
// its machine key + user ID
// ============================================================================

func TestRapid_Snapshot_NodesByMachineKeyConsistency(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		for _, node := range snap.nodesByID {
			userMap, ok := snap.nodesByMachineKey[node.MachineKey]
			if !ok {
				t.Fatalf("node %d MachineKey missing from nodesByMachineKey", node.ID)
			}

			typedUID := node.TypedUserID()
			nv, ok := userMap[typedUID]
			if !ok {
				t.Fatalf("node %d not found in nodesByMachineKey[MK][UserID=%d]",
					node.ID, typedUID)
			}
			if nv.ID() != node.ID {
				t.Fatalf("nodesByMachineKey lookup for node %d returned node %d",
					node.ID, nv.ID())
			}
		}
	})
}

// ============================================================================
// Property 5: nodesByUser excludes tagged nodes
// ============================================================================

func TestRapid_Snapshot_NodesByUserExcludesTaggedNodes(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		for uid, userNodes := range snap.nodesByUser {
			for _, nv := range userNodes {
				if nv.IsTagged() {
					t.Fatalf("tagged node %d (tags=%v) found in nodesByUser[%d]",
						nv.ID(), nv.Tags().AsSlice(), uid)
				}
			}
		}
	})
}

// ============================================================================
// Property 6: nodesByUser includes all user-owned (untagged) nodes
// ============================================================================

func TestRapid_Snapshot_NodesByUserIncludesUserOwnedNodes(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		for _, node := range nodes {
			if node.IsTagged() {
				continue
			}

			uid := node.TypedUserID()
			userNodes, ok := snap.nodesByUser[uid]
			if !ok {
				t.Fatalf("user-owned node %d (user=%d) has no entry in nodesByUser",
					node.ID, uid)
			}

			found := false
			for _, nv := range userNodes {
				if nv.ID() == node.ID {
					found = true
					break
				}
			}
			if !found {
				t.Fatalf("user-owned node %d not found in nodesByUser[%d]",
					node.ID, uid)
			}
		}
	})
}

// ============================================================================
// Property 7: peersByNode self-exclusion — no node appears in its own peer list
// ============================================================================

func TestRapid_Snapshot_PeersByNodeSelfExclusion(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(20).Draw(t, "nodes")
		ids := nodeIDs(nodes)
		pf := genPeersFunc(t, ids)
		snap := snapshotFromNodes(nodes, pf)

		for nodeID, peers := range snap.peersByNode {
			for _, peer := range peers {
				if peer.ID() == nodeID {
					t.Fatalf("node %d appears in its own peer list", nodeID)
				}
			}
		}
	})
}

// ============================================================================
// Property 8: peersByNode symmetry — with a symmetric PeersFunc, if Y is in
// peers(X) then X is in peers(Y)
// ============================================================================

func TestRapid_Snapshot_PeersByNodeSymmetry(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(20).Draw(t, "nodes")
		ids := nodeIDs(nodes)
		// Always use the symmetric random PeersFunc for this property.
		pf := symmetricRandomPeersFunc(t, ids)
		snap := snapshotFromNodes(nodes, pf)

		for nodeID, peers := range snap.peersByNode {
			for _, peer := range peers {
				// peer.ID() should have nodeID in its peers
				reversePeers, ok := snap.peersByNode[peer.ID()]
				if !ok {
					t.Fatalf("node %d is peer of %d but %d has no peersByNode entry",
						peer.ID(), nodeID, peer.ID())
				}

				found := false
				for _, rp := range reversePeers {
					if rp.ID() == nodeID {
						found = true
						break
					}
				}
				if !found {
					t.Fatalf("symmetry violation: %d in peers(%d), but %d not in peers(%d)",
						peer.ID(), nodeID, nodeID, peer.ID())
				}
			}
		}
	})
}

// ============================================================================
// Property 9: allNodes is NOT sorted by ID
//
// This test was originally written to assert that allNodes is sorted by ID.
// Rapid immediately found a counterexample: snapshotFromNodes iterates over
// a Go map (nondeterministic order) and does NOT sort allNodes. This is a
// deliberate design choice — the slice is used for iteration, not binary
// search, so sorting would be unnecessary overhead.
//
// We keep the test inverted to document and protect this behavior: if someone
// adds sorting in the future, this test will catch the change so the team can
// decide whether to update callers or revert.
// ============================================================================

func TestRapid_Snapshot_AllNodesNotSortedInvariant(t *testing.T) {
	// We verify that allNodes contains the correct IDs (unordered) and that
	// there are no duplicates, which IS an invariant.
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		seen := make(map[types.NodeID]bool, len(snap.allNodes))
		for _, nv := range snap.allNodes {
			if seen[nv.ID()] {
				t.Fatalf("duplicate ID %d in allNodes", nv.ID())
			}
			seen[nv.ID()] = true
		}

		// Every input ID must appear.
		for id := range nodes {
			if !seen[id] {
				t.Fatalf("node %d missing from allNodes", id)
			}
		}

		// No extra IDs.
		if len(seen) != len(nodes) {
			t.Fatalf("allNodes has %d unique IDs, input has %d", len(seen), len(nodes))
		}
	})
}

// ============================================================================
// Property 10: Empty input produces empty snapshot
// ============================================================================

func TestRapid_Snapshot_EmptyInputEmptySnapshot(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		// Use any PeersFunc strategy — doesn't matter for empty input.
		strategy := rapid.IntRange(0, 1).Draw(t, "strategy")
		var pf PeersFunc
		if strategy == 0 {
			pf = allVisiblePeersFunc
		} else {
			pf = noVisiblePeersFunc
		}

		snap := snapshotFromNodes(map[types.NodeID]types.Node{}, pf)

		if len(snap.allNodes) != 0 {
			t.Fatalf("empty input: allNodes has %d entries", len(snap.allNodes))
		}
		if len(snap.nodesByID) != 0 {
			t.Fatalf("empty input: nodesByID has %d entries", len(snap.nodesByID))
		}
		if len(snap.nodesByNodeKey) != 0 {
			t.Fatalf("empty input: nodesByNodeKey has %d entries", len(snap.nodesByNodeKey))
		}
		if len(snap.nodesByMachineKey) != 0 {
			t.Fatalf("empty input: nodesByMachineKey has %d entries", len(snap.nodesByMachineKey))
		}
		if len(snap.nodesByUser) != 0 {
			t.Fatalf("empty input: nodesByUser has %d entries", len(snap.nodesByUser))
		}
		if len(snap.peersByNode) != 0 {
			t.Fatalf("empty input: peersByNode has %d entries", len(snap.peersByNode))
		}
	})
}

// ============================================================================
// Bonus properties
// ============================================================================

// Property: nodesByUser partitions the untagged nodes — the total count of
// entries across all user buckets equals the number of untagged input nodes.
func TestRapid_Snapshot_NodesByUserPartitionsUntagged(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		// Count untagged nodes in input.
		untaggedCount := 0
		for _, node := range nodes {
			if !node.IsTagged() {
				untaggedCount++
			}
		}

		// Count total entries in nodesByUser.
		userNodeCount := 0
		for _, userNodes := range snap.nodesByUser {
			userNodeCount += len(userNodes)
		}

		if userNodeCount != untaggedCount {
			t.Fatalf("nodesByUser total entries %d != untagged input count %d",
				userNodeCount, untaggedCount)
		}
	})
}

// Property: allNodes contains exactly the same set of IDs as nodesByID.
func TestRapid_Snapshot_AllNodesMatchesNodesByID(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(30).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		// Collect IDs from allNodes.
		allNodeIDs := make(map[types.NodeID]bool, len(snap.allNodes))
		for _, nv := range snap.allNodes {
			if allNodeIDs[nv.ID()] {
				t.Fatalf("duplicate ID %d in allNodes", nv.ID())
			}
			allNodeIDs[nv.ID()] = true
		}

		// Compare with nodesByID.
		for id := range snap.nodesByID {
			if !allNodeIDs[id] {
				t.Fatalf("nodesByID has ID %d not found in allNodes", id)
			}
		}
		for id := range allNodeIDs {
			if _, ok := snap.nodesByID[id]; !ok {
				t.Fatalf("allNodes has ID %d not found in nodesByID", id)
			}
		}
	})
}

// Property: with allVisiblePeersFunc, every node sees exactly N-1 peers.
func TestRapid_Snapshot_AllVisiblePeersCount(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(20).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, allVisiblePeersFunc)

		n := len(nodes)
		for nodeID, peers := range snap.peersByNode {
			if len(peers) != n-1 {
				t.Fatalf("node %d has %d peers with allVisible, want %d",
					nodeID, len(peers), n-1)
			}
		}
	})
}

// Property: with noVisiblePeersFunc, every node sees zero peers.
func TestRapid_Snapshot_NoVisiblePeersCount(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(20).Draw(t, "nodes")
		snap := snapshotFromNodes(nodes, noVisiblePeersFunc)

		for nodeID, peers := range snap.peersByNode {
			if len(peers) != 0 {
				t.Fatalf("node %d has %d peers with noVisible, want 0",
					nodeID, len(peers))
			}
		}
	})
}

// Property: peersByNode has an entry for every node in the input (the PeersFunc
// is called with all nodes and should return an entry per node).
func TestRapid_Snapshot_PeersByNodeCompleteness(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		nodes := genNodeMap(20).Draw(t, "nodes")
		ids := nodeIDs(nodes)
		pf := genPeersFunc(t, ids)
		snap := snapshotFromNodes(nodes, pf)

		for id := range nodes {
			if _, ok := snap.peersByNode[id]; !ok {
				t.Fatalf("node %d missing from peersByNode", id)
			}
		}
	})
}

package state

import (
	"errors"
	"testing"

	"github.com/juanfont/headscale/hscontrol/types"
	"pgregory.net/rapid"
)

// ptrOf returns a pointer to the given value.
func ptrOf[T any](v T) *T {
	return &v
}

// ============================================================================
// Generators
// ============================================================================

// genNonEmptyTags generates a slice of 1..maxLen unique "tag:name" tags.
func genNonEmptyTags(maxLen int) *rapid.Generator[[]string] {
	return rapid.Custom[[]string](func(t *rapid.T) []string {
		n := rapid.IntRange(1, maxLen).Draw(t, "numTags")
		seen := make(map[string]bool, n)
		result := make([]string, 0, n)
		for len(result) < n {
			tag := genTag().Draw(t, "tag")
			if !seen[tag] {
				seen[tag] = true
				result = append(result, tag)
			}
		}
		return result
	})
}

// ============================================================================
// validateNodeOwnership: 4-quadrant property tests
// ============================================================================

// Quadrant 1: tagged node + no UserID -> ok
func TestRapid_ValidateNodeOwnership_TaggedNoUser_OK(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		tags := genNonEmptyTags(5).Draw(t, "tags")
		hostname := rapid.StringMatching(`[a-z][a-z0-9]{2,10}`).Draw(t, "hostname")

		node := &types.Node{
			Hostname: hostname,
			Tags:     tags,
			UserID:   nil,
		}

		err := validateNodeOwnership(node)
		if err != nil {
			t.Fatalf("tagged node without UserID should be valid, got: %v", err)
		}
	})
}

// Quadrant 2: tagged node + UserID set -> error (ErrTaggedNodeHasUser)
func TestRapid_ValidateNodeOwnership_TaggedWithUser_Error(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		tags := genNonEmptyTags(5).Draw(t, "tags")
		uid := genUserID().Draw(t, "uid")
		hostname := rapid.StringMatching(`[a-z][a-z0-9]{2,10}`).Draw(t, "hostname")

		node := &types.Node{
			Hostname: hostname,
			Tags:     tags,
			UserID:   ptrOf(uid),
		}

		err := validateNodeOwnership(node)
		if err == nil {
			t.Fatalf("tagged node with UserID should fail, but got nil")
		}
		if !errors.Is(err, ErrTaggedNodeHasUser) {
			t.Fatalf("expected ErrTaggedNodeHasUser, got: %v", err)
		}
	})
}

// Quadrant 3: not tagged + no UserID -> error (ErrNodeHasNeitherUserNorTags)
func TestRapid_ValidateNodeOwnership_UntaggedNoUser_Error(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		hostname := rapid.StringMatching(`[a-z][a-z0-9]{2,10}`).Draw(t, "hostname")

		node := &types.Node{
			Hostname: hostname,
			Tags:     nil,
			UserID:   nil,
		}

		err := validateNodeOwnership(node)
		if err == nil {
			t.Fatal("untagged node without UserID should fail, but got nil")
		}
		if !errors.Is(err, ErrNodeHasNeitherUserNorTags) {
			t.Fatalf("expected ErrNodeHasNeitherUserNorTags, got: %v", err)
		}
	})
}

// Quadrant 4: not tagged + UserID set -> ok
func TestRapid_ValidateNodeOwnership_UntaggedWithUser_OK(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		uid := genUserID().Draw(t, "uid")
		hostname := rapid.StringMatching(`[a-z][a-z0-9]{2,10}`).Draw(t, "hostname")

		node := &types.Node{
			Hostname: hostname,
			Tags:     nil,
			UserID:   ptrOf(uid),
		}

		err := validateNodeOwnership(node)
		if err != nil {
			t.Fatalf("untagged node with UserID should be valid, got: %v", err)
		}
	})
}

// Property: validateNodeOwnership always returns nil xor an error for any
// combination of tags and userID. This tests that all 4 quadrants are covered
// exhaustively and there are no panics.
func TestRapid_ValidateNodeOwnership_NoPanic(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		tags := genTags(5).Draw(t, "tags")
		hasUser := rapid.Bool().Draw(t, "hasUser")
		hostname := rapid.StringMatching(`[a-z][a-z0-9]{2,10}`).Draw(t, "hostname")

		var userID *uint
		if hasUser {
			uid := genUserID().Draw(t, "uid")
			userID = ptrOf(uid)
		}

		node := &types.Node{
			Hostname: hostname,
			Tags:     tags,
			UserID:   userID,
		}

		// Should not panic
		err := validateNodeOwnership(node)

		isTagged := len(tags) > 0
		hasUID := userID != nil

		switch {
		case isTagged && !hasUID:
			if err != nil {
				t.Fatalf("tagged+noUser should be ok, got: %v", err)
			}
		case isTagged && hasUID:
			if !errors.Is(err, ErrTaggedNodeHasUser) {
				t.Fatalf("tagged+user should be ErrTaggedNodeHasUser, got: %v", err)
			}
		case !isTagged && !hasUID:
			if !errors.Is(err, ErrNodeHasNeitherUserNorTags) {
				t.Fatalf("untagged+noUser should be ErrNodeHasNeitherUserNorTags, got: %v", err)
			}
		case !isTagged && hasUID:
			if err != nil {
				t.Fatalf("untagged+user should be ok, got: %v", err)
			}
		}
	})
}

// Property: tagged nodes with empty Tags slice (but IsTagged checks len > 0)
// are actually not tagged, so they fall into the "untagged" path.
func TestRapid_ValidateNodeOwnership_EmptyTagsEqualsUntagged(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		uid := genUserID().Draw(t, "uid")
		hostname := rapid.StringMatching(`[a-z][a-z0-9]{2,10}`).Draw(t, "hostname")

		node := &types.Node{
			Hostname: hostname,
			Tags:     []string{},
			UserID:   ptrOf(uid),
		}

		// Empty tags = not tagged, so user-owned node with UserID should be valid.
		err := validateNodeOwnership(node)
		if err != nil {
			t.Fatalf("empty tags + UserID should be valid (user-owned), got: %v", err)
		}

		// Empty tags + no UserID should fail.
		nodeNoUser := &types.Node{
			Hostname: hostname,
			Tags:     []string{},
			UserID:   nil,
		}
		err = validateNodeOwnership(nodeNoUser)
		if !errors.Is(err, ErrNodeHasNeitherUserNorTags) {
			t.Fatalf("empty tags + no UserID should be ErrNodeHasNeitherUserNorTags, got: %v", err)
		}
	})
}

package types

