// -----------------------------------------------------------------------
// Property 13: uniqueNodeIDs properties
//   - idempotent
//   - output is sorted with no duplicates
//   - preserves all input values (set equivalence)
//   - nil/empty → nil
// -----------------------------------------------------------------------

func TestRapid_UniqueNodeIDsProperties(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		raw := genNodeIDSlice(t)
		// Work on a copy because uniqueNodeIDs sorts in-place.
		ids := make([]types.NodeID, len(raw))
		copy(ids, raw)

		result := uniqueNodeIDs(ids)

		if len(raw) == 0 {
			if result != nil {
				t.Fatalf("uniqueNodeIDs(empty) = %v, want nil", result)
			}
			return
		}

		// Sorted.
		if !slices.IsSorted(result) {
			t.Fatalf("not sorted: %v", result)
		}

		// No duplicates.
		for i := 1; i < len(result); i++ {
			if result[i] == result[i-1] {
				t.Fatalf("duplicate at %d: %v", i, result)
			}
		}

		// Preserves all input values.
		resultSet := make(map[types.NodeID]bool, len(result))
		for _, id := range result {
			resultSet[id] = true
		}
		for _, id := range raw {
			if !resultSet[id] {
				t.Fatalf("dropped %d: input=%v, output=%v", id, raw, result)
			}
		}

		// No extra values.
		inputSet := make(map[types.NodeID]bool, len(raw))
		for _, id := range raw {
			inputSet[id] = true
		}
		for _, id := range result {
			if !inputSet[id] {
				t.Fatalf("introduced %d: input=%v, output=%v", id, raw, result)
			}
		}

		// Idempotent.
		r2 := make([]types.NodeID, len(result))
		copy(r2, result)
		double := uniqueNodeIDs(r2)
		if !slices.Equal(result, double) {
			t.Fatalf("not idempotent: first=%v, second=%v", result, double)
		}

		// Output length ≤ input length.
		if len(result) > len(raw) {
			t.Fatalf("output (%d) longer than input (%d)", len(result), len(raw))
		}
	})
}

