// Reason merge semantics (exhaustive case analysis).
func TestRapid_ReasonMergeSemantics(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		a := genChange(t)
		b := genChange(t)

		merged := cloneChange(a).Merge(cloneChange(b))

		switch {
		case a.Reason != "" && b.Reason != "" && a.Reason != b.Reason:
			want := a.Reason + "; " + b.Reason
			if merged.Reason != want {
				t.Fatalf("different reasons: want %q, got %q", want, merged.Reason)
			}
		case a.Reason != "" && b.Reason != "" && a.Reason == b.Reason:
			if merged.Reason != a.Reason {
				t.Fatalf("same reasons: want %q, got %q", a.Reason, merged.Reason)
			}
		case a.Reason == "" && b.Reason != "":
			if merged.Reason != b.Reason {
				t.Fatalf("a empty: want %q, got %q", b.Reason, merged.Reason)
			}
		case a.Reason != "" && b.Reason == "":
			if merged.Reason != a.Reason {
				t.Fatalf("b empty: want %q, got %q", a.Reason, merged.Reason)
			}
		default: // both empty
			if merged.Reason != "" {
				t.Fatalf("both empty: want \"\", got %q", merged.Reason)
			}
		}
	})
}

