func TestRapid_TailNode_IDPreservation(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		inp := genTailNodeInput().Draw(t, "input")
		out, err := callTailNode(inp)
		if err != nil {
			t.Fatalf("TailNode error: %v", err)
