	rapid.Check(t, func(t *rapid.T) {
		input := rapid.StringOfN(rapid.Rune(), 0, 80, -1).Draw(t, "input")

		first := CleanIdentifier(input)
		second := CleanIdentifier(first)

		if first != second {
			t.Fatalf("CleanIdentifier not idempotent: first=%q, second=%q (input=%q)",
				first, second, input)
		}
	})
}

