// Property: CleanIdentifier preserves URL scheme.
func TestRapid_CleanIdentifier_PreservesScheme(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		issuer := genURLIssuer().Draw(t, "url")

