## Generator Strategies for Headscale Domain Objects

Following Hillel Wayne's guidance on constructive generation, here's how to build composite generators:

```go
// 1. Generate the "universe" first
func generateTestUniverse(t *rapid.T) *TestUniverse {
    numUsers := rapid.IntRange(1, 5).Draw(t, "numUsers")
    users := make([]types.User, numUsers)
    for i := range users {
        users[i] = types.User{
            Model: gorm.Model{ID: uint(i + 1)},
            Name:  fmt.Sprintf("user%d", i+1),
        }
    }

    // Generate nodes belonging to users, with IPs in a prefix
    prefix4 := netip.MustParsePrefix("100.64.0.0/24")
    numNodes := rapid.IntRange(2, 10).Draw(t, "numNodes")
    nodes := make([]types.Node, numNodes)
    for i := range nodes {
        userIdx := rapid.IntRange(0, numUsers-1).Draw(t, fmt.Sprintf("node%d_user", i))
        nodes[i] = types.Node{
            ID:       types.NodeID(i + 1),
            IPv4:     addrPtr(netip.AddrFrom4([4]byte{100, 64, 0, byte(i + 1)})),
            UserID:   &users[userIdx].ID,
            Hostname: fmt.Sprintf("node%d", i+1),
        }
    }

    return &TestUniverse{Users: users, Nodes: nodes, Prefix4: prefix4}
}

// 2. Generate ACL rules that reference valid entities from the universe
func generateACLRule(t *rapid.T, u *TestUniverse) ACL {
    srcType := rapid.IntRange(0, 2).Draw(t, "srcType")
    var src Aliases
    switch srcType {
    case 0: // user reference
        user := rapid.SampledFrom(u.Users).Draw(t, "srcUser")
        src = Aliases{&Username{Name: user.Name}}
    case 1: // wildcard
        src = Aliases{&Asterix{}}
    case 2: // specific IP
        node := rapid.SampledFrom(u.Nodes).Draw(t, "srcNode")
        src = Aliases{&Prefix{netip.PrefixFrom(*node.IPv4, 32)}}
    }
    // ... similar for destinations
    return ACL{Action: ActionAccept, Sources: src, Destinations: dsts}
}
```

This constructive approach ensures every generated ACL rule references entities that actually exist in the test universe, avoiding the invalid-input-filtering problem.

