Here is a comprehensive guide to property-based testing with `pgregory.net/rapid` for the network types used throughout headscale.

## 1. Generators for `net/netip` Types

### Core IP Address Generators

```go
package netgen

import (
    "encoding/binary"
    "net/netip"

    "go4.org/netipx"
    "pgregory.net/rapid"
    "tailscale.com/tailcfg"
)

// --- netip.Addr generators ---

// IPv4 generates an arbitrary valid IPv4 address.
func IPv4() *rapid.Generator[netip.Addr] {
    return rapid.Custom(func(t *rapid.T) netip.Addr {
        b := [4]byte{
            rapid.Byte().Draw(t, "b0"),
            rapid.Byte().Draw(t, "b1"),
            rapid.Byte().Draw(t, "b2"),
            rapid.Byte().Draw(t, "b3"),
        }
        return netip.AddrFrom4(b)
    })
}

// IPv6 generates an arbitrary valid IPv6 address.
func IPv6() *rapid.Generator[netip.Addr] {
    return rapid.Custom(func(t *rapid.T) netip.Addr {
        var b [16]byte
        for i := range b {
            b[i] = rapid.Byte().Draw(t, "b")
        }
        return netip.AddrFrom16(b)
    })
}

// Addr generates either an IPv4 or IPv6 address.
func Addr() *rapid.Generator[netip.Addr] {
    return rapid.OneOf(IPv4(), IPv6())
}
```

### Generators for Headscale-Specific IP Ranges

```go
// CGNAT range: 100.64.0.0/10 (100.64.0.0 - 100.127.255.255)
// Used by Tailscale/headscale for IPv4 node addresses.
func CGNATAddr() *rapid.Generator[netip.Addr] {
    return rapid.Custom(func(t *rapid.T) netip.Addr {
        // 100.64.0.0/10 means first 10 bits are fixed: 01100100 01
        // Byte 0 = 100 (0x64), Byte 1 high 2 bits = 01 (0x40..0x7F)
        b1 := rapid.ByteRange(64, 127).Draw(t, "b1") // 0x40-0x7F
        b2 := rapid.Byte().Draw(t, "b2")
        b3 := rapid.Byte().Draw(t, "b3")
        return netip.AddrFrom4([4]byte{100, b1, b2, b3})
    })
}

// ULA range: fd7a:115c:a1e0::/48
// Used by Tailscale/headscale for IPv6 node addresses.
func TailscaleULAAddr() *rapid.Generator[netip.Addr] {
    return rapid.Custom(func(t *rapid.T) netip.Addr {
        // Fixed prefix: fd7a:115c:a1e0 (first 48 bits = 6 bytes)
        var b [16]byte
        b[0] = 0xfd
        b[1] = 0x7a
        b[2] = 0x11
        b[3] = 0x5c
        b[4] = 0xa1
        b[5] = 0xe0
        // Remaining 10 bytes are random
        for i := 6; i < 16; i++ {
            b[i] = rapid.Byte().Draw(t, "b")
        }
        return netip.AddrFrom16(b)
    })
}

// AddrInPrefix generates a random address within a given prefix.
// This is the most general form — works for any prefix.
func AddrInPrefix(pfx netip.Prefix) *rapid.Generator[netip.Addr] {
    return rapid.Custom(func(t *rapid.T) netip.Addr {
        rng := netipx.RangeOfPrefix(pfx)
        from, to := rng.From(), rng.To()
        fromBytes := from.As16()
        toBytes := to.As16()

        var out [16]byte
        for i := range out {
            lo, hi := fromBytes[i], toBytes[i]
            if lo == hi {
                out[i] = lo
            } else {
                out[i] = rapid.ByteRange(lo, hi).Draw(t, "b")
            }
        }

        addr := netip.AddrFrom16(out)
        // For IPv4-in-IPv6 mapped addresses, unmap
        if pfx.Addr().Is4() {
            addr = addr.Unmap()
        }
        // Filter ensures we stay within the prefix (byte-range
        // generation can overshoot for non-byte-aligned prefixes)
        if !pfx.Contains(addr) {
            t.Fatalf("generated addr %s not in prefix %s, retrying", addr, pfx)
        }
        return addr
    })
}
```

**Important note on `AddrInPrefix`**: The byte-range approach can overshoot for non-byte-aligned prefixes (e.g., `/10`, `/48`). A more robust approach uses `rapid.Filter` or generates a random offset:

```go
// AddrInPrefixRobust handles non-byte-aligned prefixes correctly.
func AddrInPrefixRobust(pfx netip.Prefix) *rapid.Generator[netip.Addr] {
    rng := netipx.RangeOfPrefix(pfx)
    from, to := rng.From(), rng.To()

    fromU := addrToUint128(from)
    toU := addrToUint128(to)
    rangeSize := toU.sub(fromU)

    return rapid.Custom(func(t *rapid.T) netip.Addr {
        // Generate a random offset within [0, rangeSize]
        hi := rapid.Uint64Range(0, rangeSize.hi).Draw(t, "hi")
        var lo uint64
        if hi == rangeSize.hi {
            lo = rapid.Uint64Range(0, rangeSize.lo).Draw(t, "lo")
        } else {
            lo = rapid.Uint64().Draw(t, "lo")
        }

        result := fromU.add(uint128{hi, lo})
        return uint128ToAddr(result, pfx.Addr().Is4())
    })
}

// uint128 for IP arithmetic
type uint128 struct{ hi, lo uint64 }

func (a uint128) add(b uint128) uint128 {
    lo := a.lo + b.lo
    hi := a.hi + b.hi
    if lo < a.lo { hi++ } // carry
    return uint128{hi, lo}
}

func (a uint128) sub(b uint128) uint128 {
    lo := a.lo - b.lo
    hi := a.hi - b.hi
    if a.lo < b.lo { hi-- } // borrow
    return uint128{hi, lo}
}

func addrToUint128(a netip.Addr) uint128 {
    b := a.As16()
    return uint128{
        hi: binary.BigEndian.Uint64(b[:8]),
        lo: binary.BigEndian.Uint64(b[8:]),
    }
}

func uint128ToAddr(u uint128, is4 bool) netip.Addr {
    var b [16]byte
    binary.BigEndian.PutUint64(b[:8], u.hi)
    binary.BigEndian.PutUint64(b[8:], u.lo)
    addr := netip.AddrFrom16(b)
    if is4 {
        return addr.Unmap()
    }
    return addr
}
```

### Prefix Generator

```go
// IPv4Prefix generates a valid IPv4 prefix with proper masking.
func IPv4Prefix() *rapid.Generator[netip.Prefix] {
    return rapid.Custom(func(t *rapid.T) netip.Prefix {
        addr := IPv4().Draw(t, "addr")
        bits := rapid.IntRange(0, 32).Draw(t, "bits")
        pfx := netip.PrefixFrom(addr, bits)
        return pfx.Masked() // Ensure canonical form (no host bits set)
    })
}

// IPv6Prefix generates a valid IPv6 prefix with proper masking.
func IPv6Prefix() *rapid.Generator[netip.Prefix] {
    return rapid.Custom(func(t *rapid.T) netip.Prefix {
        addr := IPv6().Draw(t, "addr")
        bits := rapid.IntRange(0, 128).Draw(t, "bits")
        pfx := netip.PrefixFrom(addr, bits)
        return pfx.Masked()
    })
}

// Prefix generates either an IPv4 or IPv6 prefix.
func Prefix() *rapid.Generator[netip.Prefix] {
    return rapid.OneOf(IPv4Prefix(), IPv6Prefix())
}

// PrefixInRange generates a prefix that is a subnet of the given parent.
func PrefixInRange(parent netip.Prefix) *rapid.Generator[netip.Prefix] {
    return rapid.Custom(func(t *rapid.T) netip.Prefix {
        maxBits := parent.Addr().BitLen() // 32 or 128
        bits := rapid.IntRange(parent.Bits(), maxBits).Draw(t, "bits")
        addr := AddrInPrefixRobust(parent).Draw(t, "addr")
        pfx := netip.PrefixFrom(addr, bits)
        return pfx.Masked()
    })
}
```

### AddrPort Generator

```go
// AddrPort generates a valid netip.AddrPort.
func AddrPort() *rapid.Generator[netip.AddrPort] {
    return rapid.Custom(func(t *rapid.T) netip.AddrPort {
        addr := Addr().Draw(t, "addr")
        port := rapid.Uint16().Draw(t, "port")
        return netip.AddrPortFrom(addr, port)
    })
}
