## 2. Port Range Generators

These match `tailcfg.PortRange` used extensively in headscale's policy engine (`hscontrol/policy/v2/utils.go:86-136`):

```go
// PortRange generates a valid tailcfg.PortRange where First <= Last.
func PortRange() *rapid.Generator[tailcfg.PortRange] {
    return rapid.Custom(func(t *rapid.T) tailcfg.PortRange {
        first := rapid.Uint16Range(1, 65535).Draw(t, "first")
        last := rapid.Uint16Range(first, 65535).Draw(t, "last")
        return tailcfg.PortRange{First: first, Last: last}
    })
}

// PortRangeAnyOrSpecific generates either PortRangeAny or a specific range.
func PortRangeAnyOrSpecific() *rapid.Generator[tailcfg.PortRange] {
    return rapid.OneOf(
        rapid.Just(tailcfg.PortRangeAny),
        PortRange(),
    )
}

// SinglePort generates a PortRange for a single port.
func SinglePort() *rapid.Generator[tailcfg.PortRange] {
    return rapid.Custom(func(t *rapid.T) tailcfg.PortRange {
        p := rapid.Uint16Range(1, 65535).Draw(t, "port")
        return tailcfg.PortRange{First: p, Last: p}
    })
}

// PortRanges generates a slice of non-overlapping port ranges.
func NonOverlappingPortRanges() *rapid.Generator[[]tailcfg.PortRange] {
    return rapid.Custom(func(t *rapid.T) []tailcfg.PortRange {
        n := rapid.IntRange(1, 5).Draw(t, "n")
        // Generate n distinct boundaries in [1, 65535]
        boundaries := rapid.SliceOfNDistinct(
            rapid.Uint16Range(1, 65535),
            n*2, n*2, rapid.ID[uint16],
        ).Draw(t, "boundaries")
        slices.Sort(boundaries)

        var ranges []tailcfg.PortRange
        for i := 0; i < len(boundaries)-1; i += 2 {
            ranges = append(ranges, tailcfg.PortRange{
                First: boundaries[i],
                Last:  boundaries[i+1],
            })
        }
        return ranges
    })
}
```

## 3. IPSet Generators

The `netipx.IPSet` type is immutable (built via `IPSetBuilder`), used heavily in the policy engine at `hscontrol/policy/v2/types.go` and `hscontrol/policy/v2/filter.go`. These generators create IPSets with different coverage properties:

```go
// IPSet generates an IPSet from a random collection of prefixes.
func IPSet() *rapid.Generator[*netipx.IPSet] {
    return rapid.Custom(func(t *rapid.T) *netipx.IPSet {
        prefixes := rapid.SliceOfN(Prefix(), 0, 10).Draw(t, "prefixes")
        var b netipx.IPSetBuilder
        for _, p := range prefixes {
            b.AddPrefix(p)
        }
        set, err := b.IPSet()
        if err != nil {
            t.Fatalf("building IPSet: %v", err)
        }
        return set
    })
}

// IPv4IPSet generates an IPSet containing only IPv4 prefixes.
func IPv4IPSet() *rapid.Generator[*netipx.IPSet] {
    return rapid.Custom(func(t *rapid.T) *netipx.IPSet {
        prefixes := rapid.SliceOfN(IPv4Prefix(), 0, 10).Draw(t, "prefixes")
        var b netipx.IPSetBuilder
        for _, p := range prefixes {
            b.AddPrefix(p)
        }
        set, _ := b.IPSet()
        return set
    })
}

// DisjointIPSets generates two IPSets guaranteed to have no overlap.
func DisjointIPSets() *rapid.Generator[[2]*netipx.IPSet] {
    return rapid.Custom(func(t *rapid.T) [2]*netipx.IPSet {
        // Use the left and right halves of the IPv4 space
        set1Prefixes := rapid.SliceOfN(
            PrefixInRange(netip.MustParsePrefix("0.0.0.0/1")),
            1, 5,
        ).Draw(t, "set1")

        set2Prefixes := rapid.SliceOfN(
            PrefixInRange(netip.MustParsePrefix("128.0.0.0/1")),
            1, 5,
        ).Draw(t, "set2")

        var b1, b2 netipx.IPSetBuilder
        for _, p := range set1Prefixes {
            b1.AddPrefix(p)
        }
        for _, p := range set2Prefixes {
            b2.AddPrefix(p)
        }
        s1, _ := b1.IPSet()
        s2, _ := b2.IPSet()
        return [2]*netipx.IPSet{s1, s2}
    })
}

// OverlappingIPSets generates two IPSets that share at least one common prefix.
func OverlappingIPSets() *rapid.Generator[[2]*netipx.IPSet] {
    return rapid.Custom(func(t *rapid.T) [2]*netipx.IPSet {
        shared := rapid.SliceOfN(IPv4Prefix(), 1, 3).Draw(t, "shared")
        extra1 := rapid.SliceOfN(IPv4Prefix(), 0, 3).Draw(t, "extra1")
        extra2 := rapid.SliceOfN(IPv4Prefix(), 0, 3).Draw(t, "extra2")

        var b1, b2 netipx.IPSetBuilder
        for _, p := range shared {
            b1.AddPrefix(p)
            b2.AddPrefix(p)
        }
        for _, p := range extra1 {
            b1.AddPrefix(p)
        }
        for _, p := range extra2 {
            b2.AddPrefix(p)
        }
        s1, _ := b1.IPSet()
        s2, _ := b2.IPSet()
        return [2]*netipx.IPSet{s1, s2}
    })
}

// NestedIPSets generates a parent and child IPSet where child ⊆ parent.
func NestedIPSets() *rapid.Generator[[2]*netipx.IPSet] {
    return rapid.Custom(func(t *rapid.T) [2]*netipx.IPSet {
        parentPfx := IPv4Prefix().Draw(t, "parent")
        childPrefixes := rapid.SliceOfN(
            PrefixInRange(parentPfx), 1, 5,
        ).Draw(t, "children")

        var parentBuilder, childBuilder netipx.IPSetBuilder
        parentBuilder.AddPrefix(parentPfx)
        for _, p := range childPrefixes {
            childBuilder.AddPrefix(p)
        }
        parent, _ := parentBuilder.IPSet()
        child, _ := childBuilder.IPSet()
        return [2]*netipx.IPSet{parent, child}
    })
}

// IPSetWithRemovals generates an IPSet built with both adds and removes,
// matching the pattern used in hscontrol/util/net.go:40-62 (TheInternet).
func IPSetWithRemovals() *rapid.Generator[*netipx.IPSet] {
    return rapid.Custom(func(t *rapid.T) *netipx.IPSet {
        addPrefixes := rapid.SliceOfN(IPv4Prefix(), 1, 5).Draw(t, "adds")
        removePrefixes := rapid.SliceOfN(IPv4Prefix(), 0, 3).Draw(t, "removes")

        var b netipx.IPSetBuilder
        for _, p := range addPrefixes {
            b.AddPrefix(p)
        }
        for _, p := range removePrefixes {
            b.RemovePrefix(p)
        }
        set, _ := b.IPSet()
        return set
    })
}
```

## 4. NodeID Generator and `uniqueNodeIDs` Properties

The `uniqueNodeIDs` function at `hscontrol/types/change/change.go:213-221` does `sort + compact`. The existing table-driven tests at `change_test.go:435-479` cover basic cases but miss edge properties:

```go
import (
