        ids := rapid.SliceOf(NodeIDGen()).Draw(t, "ids")
        result := uniqueNodeIDs(slices.Clone(ids))

        // Every element in the result must appear in the input
        inputSet := make(map[types.NodeID]bool)
        for _, id := range ids {
            inputSet[id] = true
