## 5. IPSet Operation Properties

These test the set algebra that underpins the entire policy engine:

```go
func TestIPSet_ContainsAfterAdd(t *testing.T) {
    rapid.Check(t, func(t *rapid.T) {
        pfx := IPv4Prefix().Draw(t, "prefix")

        var b netipx.IPSetBuilder
        b.AddPrefix(pfx)
        set, err := b.IPSet()
        if err != nil {
            t.Fatalf("building set: %v", err)
        }

        // Every address in the prefix must be contained
        testAddr := AddrInPrefixRobust(pfx).Draw(t, "addr")
        if !set.Contains(testAddr) {
            t.Fatalf("set built from %s does not contain %s", pfx, testAddr)
        }
    })
}

func TestIPSet_RemoveExcludes(t *testing.T) {
    rapid.Check(t, func(t *rapid.T) {
        parent := IPv4Prefix().Draw(t, "parent")
        child := PrefixInRange(parent).Draw(t, "child")

        var b netipx.IPSetBuilder
        b.AddPrefix(parent)
        b.RemovePrefix(child)
        set, _ := b.IPSet()

        // Addresses in the removed child must not be in the set
        testAddr := AddrInPrefixRobust(child).Draw(t, "addr")
        if set.Contains(testAddr) {
            t.Fatalf("set contains %s after removing %s from %s",
                testAddr, child, parent)
        }
    })
}

// Union property: A ∪ B contains everything in A and B
func TestIPSet_UnionContainsBoth(t *testing.T) {
    rapid.Check(t, func(t *rapid.T) {
        pfx1 := IPv4Prefix().Draw(t, "pfx1")
        pfx2 := IPv4Prefix().Draw(t, "pfx2")

        var b1, b2, bUnion netipx.IPSetBuilder
        b1.AddPrefix(pfx1)
        b2.AddPrefix(pfx2)
        bUnion.AddPrefix(pfx1)
        bUnion.AddPrefix(pfx2)

        s1, _ := b1.IPSet()
        s2, _ := b2.IPSet()
        union, _ := bUnion.IPSet()

        addr1 := AddrInPrefixRobust(pfx1).Draw(t, "addr1")
        addr2 := AddrInPrefixRobust(pfx2).Draw(t, "addr2")

        if !union.Contains(addr1) {
            t.Fatalf("union missing addr from set1: %s", addr1)
        }
        if !union.Contains(addr2) {
            t.Fatalf("union missing addr from set2: %s", addr2)
        }
        // Union contains superset: anything in s1 or s2 is in union
        if s1.Contains(addr1) && !union.Contains(addr1) {
            t.Fatal("union is not a superset of s1")
        }
        if s2.Contains(addr2) && !union.Contains(addr2) {
            t.Fatal("union is not a superset of s2")
        }
    })
}

// Containment property for nested sets (tests Node.InIPSet pattern from
// hscontrol/types/node.go:296)
func TestIPSet_NestedContainment(t *testing.T) {
    rapid.Check(t, func(t *rapid.T) {
        sets := NestedIPSets().Draw(t, "sets")
        parent, child := sets[0], sets[1]

        // Every range in the child should be contained in the parent
        for _, rng := range child.Ranges() {
            if !parent.Contains(rng.From()) {
                t.Fatalf("parent does not contain child range start: %s", rng.From())
            }
        }
    })
}

// Disjointness property
func TestIPSet_DisjointSetsNoOverlap(t *testing.T) {
    rapid.Check(t, func(t *rapid.T) {
        sets := DisjointIPSets().Draw(t, "sets")
        s1, s2 := sets[0], sets[1]

        // Sample addresses from s1 and verify they are not in s2
        for _, rng := range s1.Ranges() {
            if s2.Contains(rng.From()) {
                t.Fatalf("disjoint sets overlap at %s", rng.From())
            }
        }
    })
}
