                parts[i] = fmt.Sprintf("%d", pr.First)
            } else {
                parts[i] = fmt.Sprintf("%d-%d", pr.First, pr.Last)
            }
        }
        s := strings.Join(parts, ",")

        result, err := parsePortRange(s)
        if err != nil {
            t.Fatalf("parsePortRange(%q) error: %v", s, err)
        }
        if len(result) != len(ranges) {
            t.Fatalf("expected %d ranges, got %d", len(ranges), len(result))
