package v2

import (
	"fmt"
	"strings"
	"testing"

	"pgregory.net/rapid"
	"tailscale.com/tailcfg"
)

// ============================================================================
// Generators
// ============================================================================

// genValidPort generates a port number in [1, 65535].
func genValidPort() *rapid.Generator[uint16] {
	return rapid.Uint16Range(1, 65535)
}

// genPortString generates a string representation of a valid port.
func genPortString() *rapid.Generator[string] {
	return rapid.Custom[string](func(t *rapid.T) string {
		port := genValidPort().Draw(t, "port")
		return fmt.Sprintf("%d", port)
	})
}

// genPortRange generates a valid "first-last" port range string where first <= last.
func genPortRange() *rapid.Generator[string] {
	return rapid.Custom[string](func(t *rapid.T) string {
		first := genValidPort().Draw(t, "first")
		last := genValidPort().Draw(t, "last")
		if first > last {
			first, last = last, first
		}
		return fmt.Sprintf("%d-%d", first, last)
	})
}

// genSimpleDest generates a simple destination (hostname or IP-like string).
func genSimpleDest() *rapid.Generator[string] {
	return rapid.SampledFrom([]string{
		"192.168.1.1", "10.0.0.0/8", "example.com",
		"host-1", "group:admin", "tag:server",
		"autogroup:internet", "100.64.0.0/10",
	})
}

// genIPv6Addr generates a valid IPv6 address string.
func genIPv6Addr() *rapid.Generator[string] {
	return rapid.SampledFrom([]string{
		"::1", "fd7a:115c:a1e0::1", "2001:db8::1",
		"fe80::1", "::ffff:192.168.1.1",
	})
}

