package routes

import (
	"fmt"
	"net/netip"
	"slices"
	"sort"
	"testing"

	"github.com/juanfont/headscale/hscontrol/types"
	"pgregory.net/rapid"
	"tailscale.com/net/tsaddr"
)

// prefixPool is a fixed set of non-exit prefixes used in the PBT.
var prefixPool = []netip.Prefix{
	netip.MustParsePrefix("10.0.0.0/24"),
	netip.MustParsePrefix("10.0.1.0/24"),
	netip.MustParsePrefix("192.168.1.0/24"),
	netip.MustParsePrefix("192.168.2.0/24"),
	netip.MustParsePrefix("172.16.0.0/16"),
	netip.MustParsePrefix("fd00::/64"),
}

// exitRoutes are the prefixes that should always be filtered out.
var exitRoutes = []netip.Prefix{
	netip.MustParsePrefix("0.0.0.0/0"),
	netip.MustParsePrefix("::/0"),
}

// allGeneratable includes both normal and exit prefixes for the generator.
var allGeneratable = append(append([]netip.Prefix{}, prefixPool...), exitRoutes...)

// genNodeID draws a small NodeID from [1, 8].
func genNodeID(t *rapid.T) types.NodeID {
	return types.NodeID(rapid.IntRange(1, 8).Draw(t, "nodeID"))
}

// genPrefixes draws a subset of allGeneratable (including possible exit routes).
func genPrefixes(t *rapid.T) []netip.Prefix {
	return rapid.SliceOfNDistinct(
		rapid.SampledFrom(allGeneratable),
		0, len(allGeneratable),
		func(p netip.Prefix) string { return p.String() },
	).Draw(t, "prefixes")
}

// referenceModel is a simple model that tracks the same state as PrimaryRoutes
// but with a straightforward implementation for comparison.
type referenceModel struct {
	// routes maps nodeID -> set of non-exit prefixes.
	routes map[types.NodeID]map[netip.Prefix]struct{}

	// primaries maps prefix -> primary nodeID.
	// Mirrors PrimaryRoutes.primaries semantics:
	// - Stability: if old primary still advertises, keep it.
	// - Selection: lowest nodeID among advertisers for new primaries.
	primaries map[netip.Prefix]types.NodeID
}

func newReferenceModel() *referenceModel {
	return &referenceModel{
		routes:    make(map[types.NodeID]map[netip.Prefix]struct{}),
		primaries: make(map[netip.Prefix]types.NodeID),
	}
}

// setRoutes mirrors PrimaryRoutes.SetRoutes logic.
// Returns (new primaries snapshot, changed bool).
func (m *referenceModel) setRoutes(node types.NodeID, prefixes []netip.Prefix) (map[netip.Prefix]types.NodeID, bool) {
	// Filter out exit routes and build the set.
	filtered := make(map[netip.Prefix]struct{})
	for _, p := range prefixes {
		if !tsaddr.IsExitRoute(p) {
			filtered[p] = struct{}{}
		}
	}

	if len(filtered) == 0 {
		delete(m.routes, node)
	} else {
		m.routes[node] = filtered
	}

	return m.recalcPrimaries()
}

// recalcPrimaries mirrors updatePrimaryLocked.
func (m *referenceModel) recalcPrimaries() (map[netip.Prefix]types.NodeID, bool) {
	// Build prefix -> sorted list of advertisers.
	advertisers := make(map[netip.Prefix][]types.NodeID)
	for nid, prefixes := range m.routes {
		for p := range prefixes {
			advertisers[p] = append(advertisers[p], nid)
		}
	}
	// Sort each list by NodeID (ascending).
	for p := range advertisers {
		sort.Slice(advertisers[p], func(i, j int) bool {
			return advertisers[p][i] < advertisers[p][j]
		})
	}

	changed := false

	// For each prefix with advertisers, determine primary.
	for prefix, nodes := range advertisers {
		if currentPrimary, ok := m.primaries[prefix]; ok {
			if slices.Contains(nodes, currentPrimary) {
				// Stability: current primary still advertises, keep it.
				continue
			}
		}
		// New primary needed: pick lowest NodeID.
		m.primaries[prefix] = nodes[0]
		changed = true
	}

	// Clean up primaries for prefixes no longer advertised.
	for prefix := range m.primaries {
		if _, ok := advertisers[prefix]; !ok {
			delete(m.primaries, prefix)
			changed = true
		}
	}

	// Return a snapshot of the primaries.
	snap := make(map[netip.Prefix]types.NodeID, len(m.primaries))
	for k, v := range m.primaries {
		snap[k] = v
	}
	return snap, changed
}

// primaryRoutesFor returns sorted primaries for a node (mirrors PrimaryRoutes.PrimaryRoutes).
func (m *referenceModel) primaryRoutesFor(id types.NodeID) []netip.Prefix {
	var routes []netip.Prefix
	for prefix, nid := range m.primaries {
		if nid == id {
			routes = append(routes, prefix)
		}
	}
	slices.SortFunc(routes, netip.Prefix.Compare)
	return routes
}

// snapshotPrimaries returns a copy of pr.primaries for comparison.
// Must be called while holding the lock or when no concurrent access exists.
func snapshotPrimaries(pr *PrimaryRoutes) map[netip.Prefix]types.NodeID {
	snap := make(map[netip.Prefix]types.NodeID, len(pr.primaries))
	for k, v := range pr.primaries {
		snap[k] = v
	}
	return snap
}

func TestPrimaryRoutesRapid(t *testing.T) {
	rapid.Check(t, func(t *rapid.T) {
		pr := New()
		model := newReferenceModel()

		t.Repeat(map[string]func(*rapid.T){
			"AddRoutes": func(t *rapid.T) {
				node := genNodeID(t)
				prefixes := genPrefixes(t)

				// Snapshot the primaries before the operation to check changed flag.
				pr.mu.Lock()
				beforePrimaries := snapshotPrimaries(pr)
				pr.mu.Unlock()

				gotChanged := pr.SetRoutes(node, prefixes...)
				_, modelChanged := model.setRoutes(node, prefixes)

				// Lock to inspect internal state for invariant checks.
				pr.mu.Lock()
				defer pr.mu.Unlock()

				checkInvariants(t, pr, model, beforePrimaries, gotChanged, modelChanged,
					fmt.Sprintf("AddRoutes(node=%d, prefixes=%v)", node, prefixes))
			},

			"RemoveNode": func(t *rapid.T) {
				node := genNodeID(t)

				pr.mu.Lock()
				beforePrimaries := snapshotPrimaries(pr)
				pr.mu.Unlock()

				gotChanged := pr.SetRoutes(node) // empty = remove
				_, modelChanged := model.setRoutes(node, nil)

				pr.mu.Lock()
				defer pr.mu.Unlock()

				checkInvariants(t, pr, model, beforePrimaries, gotChanged, modelChanged,
					fmt.Sprintf("RemoveNode(node=%d)", node))
			},

			"QueryPrimary": func(t *rapid.T) {
				node := genNodeID(t)

				gotRoutes := pr.PrimaryRoutes(node)
				wantRoutes := model.primaryRoutesFor(node)

				// Normalize nil vs empty for comparison.
				if len(gotRoutes) == 0 {
					gotRoutes = nil
				}
				if len(wantRoutes) == 0 {
					wantRoutes = nil
				}

				if !slices.Equal(gotRoutes, wantRoutes) {
					t.Fatalf("QueryPrimary(node=%d): got %v, want %v",
						node, gotRoutes, wantRoutes)
				}
			},
		})
	})
}

// checkInvariants verifies all required invariants hold after an operation.
// Caller must hold pr.mu.
func checkInvariants(
	t *rapid.T,
	pr *PrimaryRoutes,
	model *referenceModel,
	beforePrimaries map[netip.Prefix]types.NodeID,
	gotChanged bool,
	modelChanged bool,
	opDesc string,
) {
	// 1. Changed flag matches model.
	if gotChanged != modelChanged {
		t.Fatalf("%s: changed mismatch: got %v, model %v\nprimaries: %v\nmodel primaries: %v",
			opDesc, gotChanged, modelChanged, pr.primaries, model.primaries)
	}

	// 2. Changed flag is consistent with actual state delta.
	afterPrimaries := snapshotPrimaries(pr)
	actuallyChanged := !primariesEqual(beforePrimaries, afterPrimaries)
	if gotChanged != actuallyChanged {
		t.Fatalf("%s: changed=%v but before/after comparison says changed=%v\nbefore: %v\nafter: %v",
			opDesc, gotChanged, actuallyChanged, beforePrimaries, afterPrimaries)
	}

	// 3. Primaries match the reference model exactly.
	if len(pr.primaries) != len(model.primaries) {
		t.Fatalf("%s: primaries count mismatch: got %d, want %d\ngot: %v\nwant: %v",
			opDesc, len(pr.primaries), len(model.primaries), pr.primaries, model.primaries)
	}
	for prefix, gotNode := range pr.primaries {
		wantNode, ok := model.primaries[prefix]
		if !ok {
			t.Fatalf("%s: prefix %s in SUT primaries but not in model", opDesc, prefix)
		}
		if gotNode != wantNode {
			t.Fatalf("%s: primary for %s: got node %d, want %d", opDesc, prefix, gotNode, wantNode)
		}
	}

	// 4. Exactly one primary per advertised prefix (no prefix without primary).
	allAdvertised := make(map[netip.Prefix]bool)
	for _, prefixes := range pr.routes {
		for p := range prefixes {
			allAdvertised[p] = true
		}
	}
	for prefix := range allAdvertised {
		if _, ok := pr.primaries[prefix]; !ok {
			t.Fatalf("%s: prefix %s is advertised but has no primary", opDesc, prefix)
		}
	}

	// 5. No orphaned primaries (primary for prefix with no advertisers).
	for prefix := range pr.primaries {
		if !allAdvertised[prefix] {
			t.Fatalf("%s: prefix %s has a primary but no advertisers", opDesc, prefix)
		}
	}

	// 6. Primary must be a valid advertiser for the prefix.
	for prefix, nodeID := range pr.primaries {
		routes, ok := pr.routes[nodeID]
		if !ok {
			t.Fatalf("%s: primary node %d for prefix %s has no routes at all",
				opDesc, nodeID, prefix)
		}
		if !routes.Contains(prefix) {
			t.Fatalf("%s: primary node %d for prefix %s does not advertise that prefix",
				opDesc, nodeID, prefix)
		}
	}

	// 7. No exit routes stored in the system.
	for _, prefixes := range pr.routes {
		for p := range prefixes {
			if tsaddr.IsExitRoute(p) {
				t.Fatalf("%s: exit route %s found in routes", opDesc, p)
			}
		}
	}
	for p := range pr.primaries {
		if tsaddr.IsExitRoute(p) {
			t.Fatalf("%s: exit route %s found in primaries", opDesc, p)
		}
	}

	// 8. isPrimary index consistency.
	//    isPrimary should have exactly the set of nodeIDs that appear as values in primaries.
	expectedIsPrimary := make(map[types.NodeID]bool)
	for _, nodeID := range pr.primaries {
		expectedIsPrimary[nodeID] = true
	}
	if len(pr.isPrimary) != len(expectedIsPrimary) {
		t.Fatalf("%s: isPrimary size mismatch: got %d, want %d\ngot: %v\nwant: %v",
			opDesc, len(pr.isPrimary), len(expectedIsPrimary), pr.isPrimary, expectedIsPrimary)
	}
	for nodeID, val := range pr.isPrimary {
		if !val {
			t.Fatalf("%s: isPrimary[%d] = false, should not be in map", opDesc, nodeID)
		}
		if !expectedIsPrimary[nodeID] {
			t.Fatalf("%s: node %d in isPrimary but not a primary for any prefix", opDesc, nodeID)
		}
	}
	for nodeID := range expectedIsPrimary {
		if !pr.isPrimary[nodeID] {
			t.Fatalf("%s: node %d is a primary but missing from isPrimary index", opDesc, nodeID)
		}
	}

	// 9. Stability: if old primary still advertises the prefix, it must remain primary.
	for prefix, beforeNode := range beforePrimaries {
		if afterNode, ok := pr.primaries[prefix]; ok {
			// Check if the old primary still advertises this prefix.
			if routes, rok := pr.routes[beforeNode]; rok && routes.Contains(prefix) {
				if afterNode != beforeNode {
					t.Fatalf("%s: stability violation: prefix %s had primary %d which still advertises, but primary changed to %d",
						opDesc, prefix, beforeNode, afterNode)
				}
			}
		}
	}

	// 10. Deterministic selection: for new primaries (prefix not in before or
	//     old primary no longer advertises), the lowest NodeID must be chosen.
	for prefix, afterNode := range pr.primaries {
		beforeNode, wasPrimary := beforePrimaries[prefix]
		isNewSelection := false
		if !wasPrimary {
			// Entirely new prefix.
			isNewSelection = true
		} else {
			// Check if old primary stopped advertising.
			routes, rok := pr.routes[beforeNode]
			if !rok || !routes.Contains(prefix) {
				isNewSelection = true
			}
		}
		if isNewSelection {
			// Find the lowest NodeID that advertises this prefix.
			var lowestID types.NodeID
			first := true
			for nid, prefixes := range pr.routes {
				if prefixes.Contains(prefix) {
					if first || nid < lowestID {
						lowestID = nid
						first = false
					}
				}
			}
			if afterNode != lowestID {
				t.Fatalf("%s: deterministic selection violation: prefix %s should have primary %d (lowest advertiser), got %d",
					opDesc, prefix, lowestID, afterNode)
			}
		}
	}
}

// primariesEqual compares two primaries maps for equality.
func primariesEqual(a, b map[netip.Prefix]types.NodeID) bool {
	if len(a) != len(b) {
		return false
	}
	for k, v := range a {
		if bv, ok := b[k]; !ok || bv != v {
			return false
		}
	}
	return true
}

