		}
		mc.updateSentPeers(resp)

		// Remove some peers.
		toRemove := genTailcfgNodeIDSlice(5).Draw(t, "toRemove")
		removeResp := &tailcfg.MapResponse{
			ControlTime:  &now,
			PeersRemoved: toRemove,
		}
