			seen := make(map[types.NodeID]bool)
			for _, peer := range peers {
				if seen[peer.ID()] {
					t.Fatalf("duplicate peer: node %d has peer %d listed twice",
						nodeID, peer.ID())
				}
				seen[peer.ID()] = true
			}
		}
	})
}

