	rapid.Check(t, func(t *rapid.T) {
		a := genEndpointSlice(8).Draw(t, "a")
		b := genEndpointSlice(8).Draw(t, "b")

		ab := EndpointsChanged(a, b)
		ba := EndpointsChanged(b, a)

